211			Harness:     reviewRes.ReviewerHarness,
212			Model:       reviewRes.ReviewerModel,
213			InputBytes:  reviewRes.InputBytes,
214			OutputBytes: reviewRes.OutputBytes,
215			ElapsedMS:   reviewRes.DurationMS,
216		}
217		reviewBudgetExceeded := chargeReviewCost()
218		switch reviewRes.Verdict {
219		case VerdictApprove:
220			// Approved: record the verdict event and then close. The close must
221			// land AFTER the review event so the gate sees the terminal verdict.
222			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
223				Kind:      "review",
224				Summary:   "APPROVE",
225				Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
226				Actor:     in.Assignee,
227				Source:    "ddx agent execute-loop",
228				CreatedAt: now().UTC(),
229			})
230			if reviewBudgetExceeded {
231				// Reviewer cost tripped the budget cap; leave bead open so the
232				// loop's BudgetStop can stop the drain before the next claim.
233				out.Report = report
234				out.Approved = false
235				return out
236			}
237			if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
238				out.Report = report
239				out.StoreErrOp = "CloseWithEvidence"
240				out.StoreErr = cerr
241				return out
242			}
243		case VerdictRequestChanges:
244			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
245				Kind:      "review",
246				Summary:   "REQUEST_CHANGES",
247				Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
248				Actor:     in.Assignee,
249				Source:    "ddx agent execute-loop",
250				CreatedAt: now().UTC(),
251			})
252			report.Status = ExecuteBeadStatusReviewRequestChanges
253			report.Detail = "pre-close review: REQUEST_CHANGES"
254			out.Approved = false
255		case VerdictBlock:
256			rationale := strings.TrimSpace(reviewRes.Rationale)
257			if rationale == "" {
258				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
259					Kind:      "review-malfunction",
260					Summary:   "BLOCK without rationale",
261					Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
262					Actor:     in.Assignee,
263					Source:    "ddx agent execute-loop",
264					CreatedAt: now().UTC(),
265				})
266				report.Status = ExecuteBeadStatusReviewMalfunction
267				report.Detail = "pre-close review: malformed BLOCK verdict (missing rationale)"
268				report.ReviewRationale = ""
269				out.Report = report
270				out.Approved = false
271				return out
272			}
273			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
274				Kind:      "review",
275				Summary:   "BLOCK",
276				Body:      AppendEventSummary(rationale, reviewSummary),
277				Actor:     in.Assignee,
278				Source:    "ddx agent execute-loop",
279				CreatedAt: now().UTC(),
280			})
281			report.Status = ExecuteBeadStatusReviewBlock
282			report.Detail = "pre-close review: BLOCK (flagged for human)"
283			out.Approved = false
284		}
285		if reviewRes.Verdict == VerdictBlock || reviewRes.Verdict == VerdictRequestChanges {
286			_ = applyReviewTriageDecision(in.Store, in.Bead.ID, in.Assignee, now().UTC(), report.Tier)
287		}
288	
289		out.Report = report
290		return out
291	}
