293	func runPreCloseReviewGroup(ctx context.Context, reviewer BeadReviewer, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error) {
294		if reviewer == nil {
295			return nil, fmt.Errorf("review-group: reviewer required")
296		}
297		if groupReviewer, ok := reviewer.(reviewGroupReviewer); ok {
298			return groupReviewer.ReviewGroup(ctx, beadID, resultRev, impl)
299		}
300		result, err := reviewer.ReviewBead(ctx, beadID, resultRev, impl)
301		group := &ReviewGroupResult{
302			BeadID:    beadID,
303			ResultRev: resultRev,
304			Slots: []ReviewGroupSlotResult{
305				{
306					ReviewerIndex: 0,
307					Result:        result,
308				},
309			},
310		}
311		if err != nil {
312			group.Slots[0].Error = err.Error()
313		}
314		return group, err
315	}
