317	func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
318		if group == nil || len(group.Slots) == 0 {
319			return nil, fmt.Errorf("review-group: no review slots")
320		}
321		var firstApprove *ReviewResult
322		var firstNonApprove *ReviewResult
323		var firstResult *ReviewResult
324		for _, slot := range group.Slots {
325			if slot.Result != nil && firstResult == nil {
326				firstResult = slot.Result
327			}
328			if slot.Error != "" && slot.Result == nil {
329				if firstResult != nil {
330					return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
331				}
332				return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
333			}
334			if slot.Result == nil {
335				if firstResult != nil {
336					return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
337				}
338				return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
339			}
340			res := slot.Result
341			switch res.Verdict {
342			case VerdictApprove:
343				if !reviewResultHasACEvidence(res) {
344					return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
345				}
346				if firstApprove == nil {
347					firstApprove = res
348				}
349			case VerdictRequestChanges, VerdictBlock:
350				if firstNonApprove == nil {
351					firstNonApprove = res
352				}
353			default:
354				if firstNonApprove == nil {
355					firstNonApprove = res
356				}
357			}
358		}
359		if firstNonApprove != nil {
360			return firstNonApprove, nil
361		}
362		return firstApprove, nil
363	}
