453	// applyTriageAction performs the side effects for a chosen Action: writes a
454	// tier-pin hint into bead.Extra (escalate_tier), appends a needs_human label
455	// (needs_human), and always records a kind:triage-decision event.
456	func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
457		body := map[string]any{
458			"action": string(action),
459			"mode":   string(triage.FailureModeReviewBlock),
460		}
461		if pairedDegraded {
462			body["pairing_degraded"] = true
463		}
464	
465		switch action {
466		case triage.ActionEscalateTier:
467			nextTier := nextEscalatedTier(currentTier)
468			body["tier_hint"] = string(nextTier)
469			_ = store.Update(beadID, func(b *bead.Bead) {
470				if b.Extra == nil {
471					b.Extra = make(map[string]any)
472				}
473				b.Extra[TriageTierHintKey] = string(nextTier)
474			})
475		case triage.ActionNeedsHuman:
476			_ = store.Update(beadID, func(b *bead.Bead) {
477				if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
478					b.Labels = append(b.Labels, TriageNeedsHumanLabel)
479				}
480			})
481		}
482	
483		bodyJSON, _ := json.Marshal(body)
484		return store.AppendEvent(beadID, bead.BeadEvent{
485			Kind:      triageDecisionEventKind,
486			Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
487			Body:      string(bodyJSON),
488			Actor:     actor,
489			Source:    "ddx agent execute-loop",
490			CreatedAt: now,
491		})
492	}
