37	// ErrReviewVerdictUnparseable is the sentinel returned by ParseReviewVerdict
38	// when the reviewer output cannot be decoded into a valid ReviewVerdict.
39	// The execute-loop classifies it as evidence.OutcomeReviewUnparseable
40	// (retryable review-error) rather than mis-recording a BLOCK verdict.
41	var ErrReviewVerdictUnparseable = errors.New("reviewer output: unparseable JSON verdict")
42	
43	// ParseReviewVerdict decodes a reviewer agent's raw output into a
44	// ReviewVerdict. It accepts:
45	//   - raw JSON object;
46	//   - a single ```json …``` fenced block;
47	//   - mixed prose and fenced blocks where the LAST ```json block is the
48	//     verdict.
49	//
50	// It rejects:
51	//   - empty input;
52	//   - inputs containing no JSON object at all;
53	//   - JSON missing the "verdict" field;
54	//   - unknown verdict values (anything other than APPROVE,
55	//     REQUEST_CHANGES, BLOCK);
56	//   - truncated/malformed JSON.
57	//
58	// Unknown fields outside the schema are tolerated (forward-compat).
59	func ParseReviewVerdict(raw []byte) (ReviewVerdict, error) {
60		if len(strings.TrimSpace(string(raw))) == 0 {
61			return ReviewVerdict{}, fmt.Errorf("%w: empty input", ErrReviewVerdictUnparseable)
62		}
63		candidate, ok := extractJSONCandidate(string(raw))
64		if !ok {
65			return ReviewVerdict{}, fmt.Errorf("%w: no JSON object found", ErrReviewVerdictUnparseable)
66		}
67	
68		// First decode into a generic shape so we can validate the verdict
69		// field's presence and value before binding to ReviewVerdict.
70		var probe map[string]json.RawMessage
71		if err := json.Unmarshal([]byte(candidate), &probe); err != nil {
72			return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
73		}
74		rawVerdict, ok := probe["verdict"]
75		if !ok {
76			return ReviewVerdict{}, fmt.Errorf("%w: missing verdict field", ErrReviewVerdictUnparseable)
77		}
78		var verdictStr string
79		if err := json.Unmarshal(rawVerdict, &verdictStr); err != nil {
80			return ReviewVerdict{}, fmt.Errorf("%w: verdict not a string: %v", ErrReviewVerdictUnparseable, err)
81		}
82		switch Verdict(verdictStr) {
83		case VerdictApprove, VerdictRequestChanges, VerdictBlock:
84		default:
85			return ReviewVerdict{}, fmt.Errorf("%w: unknown verdict %q", ErrReviewVerdictUnparseable, verdictStr)
86		}
87	
88		var rv ReviewVerdict
89		if err := json.Unmarshal([]byte(candidate), &rv); err != nil {
90			return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
91		}
92		return rv, nil
93	}
