95	// extractJSONCandidate returns the JSON object payload from a raw reviewer
96	// output. Resolution order:
97	//  1. The last ```json … ``` fenced block (handles models that wrap output).
98	//  2. The last ``` … ``` fenced block when its body parses as a JSON object.
99	//  3. The substring from the first '{' that balances braces (handles raw
100	//     JSON or JSON with leading prose).
101	//
102	// Returns ok=false when no plausible JSON object is found.
103	func extractJSONCandidate(s string) (string, bool) {
104		if c, ok := lastFencedBlock(s, "json"); ok {
105			return strings.TrimSpace(c), true
106		}
107		if c, ok := lastFencedBlock(s, ""); ok {
108			trimmed := strings.TrimSpace(c)
109			if strings.HasPrefix(trimmed, "{") {
110				return trimmed, true
111			}
112		}
113		if c, ok := firstBalancedObject(s); ok {
114			return c, true
115		}
116		return "", false
117	}
118	
119	// lastFencedBlock returns the body of the LAST ```<lang> … ``` fenced block
120	// in s. lang="" matches any fence ("``` … ```"). Returns ok=false when no
121	// matching fence is found or the fence is unterminated.
122	func lastFencedBlock(s, lang string) (string, bool) {
123		open := "```"
124		if lang != "" {
125			open = "```" + lang
126		}
127		var found string
128		var ok bool
129		idx := 0
130		for {
131			i := indexFromAny(s, idx, open)
132			if i < 0 {
133				break
134			}
135			// Ensure the fence is followed by newline or whitespace (avoid
136			// matching ```jsonc when looking for ```json).
137			afterOpen := i + len(open)
138			if afterOpen < len(s) {
139				c := s[afterOpen]
140				if lang != "" && c != '\n' && c != '\r' && c != ' ' && c != '\t' {
141					idx = i + len(open)
142					continue
143				}
144			}
145			bodyStart := afterOpen
146			// Skip a single trailing newline after the opening fence.
147			if bodyStart < len(s) && s[bodyStart] == '\n' {
148				bodyStart++
149			} else if bodyStart+1 < len(s) && s[bodyStart] == '\r' && s[bodyStart+1] == '\n' {
150				bodyStart += 2
151			}
152			// Find closing fence.
153			j := strings.Index(s[bodyStart:], "```")
154			if j < 0 {
155				break
156			}
157			body := s[bodyStart : bodyStart+j]
158			// Strip a single trailing newline before the closing fence.
159			body = strings.TrimRight(body, "\n\r")
160			found = body
161			ok = true
162			idx = bodyStart + j + 3
163		}
164		return found, ok
165	}
166	
167	// indexFromAny is strings.Index but starting at the given offset.
168	func indexFromAny(s string, from int, sub string) int {
169		if from >= len(s) {
170			return -1
171		}
172		i := strings.Index(s[from:], sub)
173		if i < 0 {
174			return -1
175		}
176		return from + i
177	}
