179	// firstBalancedObject scans for the first '{' in s and returns the substring
180	// that closes its outermost JSON object, respecting strings and escapes.
181	// Returns ok=false on no opening brace or on an unterminated object.
182	func firstBalancedObject(s string) (string, bool) {
183		start := strings.Index(s, "{")
184		if start < 0 {
185			return "", false
186		}
187		depth := 0
188		inString := false
189		escape := false
190		for i := start; i < len(s); i++ {
191			c := s[i]
192			if escape {
193				escape = false
194				continue
195			}
196			if inString {
197				switch c {
198				case '\\':
199					escape = true
200				case '"':
201					inString = false
202				}
203				continue
204			}
205			switch c {
206			case '"':
207				inString = true
208			case '{':
209				depth++
210			case '}':
211				depth--
212				if depth == 0 {
213					return s[start : i+1], true
214				}
215			}
216		}
217		return "", false
218	}
